  1→import * as p from "@clack/prompts";
  2→import {
  3→	claudeCodeAdapter,
  4→	getAdapter,
  5→	getAvailableAdapters,
  6→	groupProjectsForCwd,
  7→	type ScannedProject,
  8→	type SessionFile,
  9→} from "@rudel/agent-adapters";
 10→import { buildCommand } from "@stricli/core";
 11→import { classifySession } from "../lib/classifier.js";
 12→import { loadCredentials } from "../lib/credentials.js";
 13→import {
 14→	loadFailedUploads,
 15→	recordFailedUpload,
 16→	removeFailedUpload,
 17→} from "../lib/failed-uploads.js";
 18→import { getGitInfo } from "../lib/git-info.js";
 19→import { getProjectOrgId } from "../lib/project-config.js";
 20→import { resolveSession } from "../lib/session-resolver.js";
 21→import {
 22→	DEFAULT_ENDPOINT,
 23→	SESSION_TAGS,
 24→	type SessionTag,
 25→} from "../lib/types.js";
 26→import { type UploadConfig, uploadSession } from "../lib/uploader.js";
 27→
 28→interface UploadFlags {
 29→	tag?: SessionTag;
 30→	endpoint: string;
 31→	classify: boolean;
 32→	dryRun: boolean;
 33→	org?: string;
 34→	retry: boolean;
 35→}
 36→
 37→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
 38→	const credentials = loadCredentials();
 39→	if (!credentials && !flags.dryRun) {
 40→		p.log.error("Not authenticated. Run `rudel login` first.");
 41→		process.exitCode = 1;
 42→		return;
 43→	}
 44→
 45→	p.intro("rudel upload");
 46→
 47→	const spin = p.spinner();
 48→	spin.start("Scanning projects...");
 49→
 50→	const adapters = getAvailableAdapters();
 51→	const allProjects: ScannedProject[] = [];
 52→	for (const adapter of adapters) {
 53→		const projects = await adapter.scanAllSessions();
 54→		allProjects.push(...projects);
 55→	}
 56→
 57→	spin.stop(`Found ${allProjects.length} project(s)`);
 58→
 59→	if (allProjects.length === 0) {
 60→		p.log.warn("No projects with sessions found.");
 61→		p.outro("Nothing to upload.");
 62→		return;
 63→	}
 64→
 65→	const cwd = process.cwd();
 66→	const grouped = groupProjectsForCwd(allProjects, cwd);
 67→
 68→	const options: Array<{
 69→		value: ScannedProject;
 70→		label: string;
 71→		hint: string;
 72→	}> = [];
 73→	const preSelected: ScannedProject[] = [];
 74→
 75→	for (const proj of grouped.current) {
 76→		options.push({
 77→			value: proj,
 78→			label: `[${getAdapterName(proj.source)}] ${proj.displayPath}`,
 79→			hint: sessionCountHint(proj.sessionCount),
 80→		});
 81→		preSelected.push(proj);
 82→	}
 83→
 84→	for (const sub of grouped.subfolders) {
 85→		const relative = sub.projectPath.slice(cwd.length + 1);
 86→		options.push({
 87→			value: sub,
 88→			label: `  [${getAdapterName(sub.source)}] ${relative}`,
 89→			hint: sessionCountHint(sub.sessionCount),
 90→		});
 91→		preSelected.push(sub);
 92→	}
 93→
 94→	for (const other of grouped.others) {
 95→		options.push({
 96→			value: other,
 97→			label: `[${getAdapterName(other.source)}] ${other.displayPath}`,
 98→			hint: sessionCountHint(other.sessionCount),
 99→		});
100→	}
101→
102→	const selected = await p.multiselect({
103→		message: "Select projects to upload",
104→		options,
105→		initialValues: preSelected,
106→		required: true,
107→	});
108→
109→	if (p.isCancel(selected)) {
110→		p.cancel("Upload cancelled.");
111→		return;
112→	}
113→
114→	const totalSessions = selected.reduce(
115→		(sum, proj) => sum + proj.sessionCount,
116→		0,
117→	);
118→	p.log.info(
119→		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
120→	);
121→
122→	const uploadConfig: UploadConfig = {
123→		endpoint: flags.endpoint,
124→		token: credentials?.token ?? "",
125→	};
126→
127→	const uploadSpin = p.spinner();
128→	uploadSpin.start("Uploading sessions...");
129→
130→	let succeeded = 0;
131→	let failed = 0;
132→	let completed = 0;
133→	const errors: Array<{ sessionId: string; project: string; error: string }> =
134→		[];
135→
136→	for (const project of selected) {
137→		const adapter = getAdapter(project.source);
138→		const gitInfo = await getGitInfo(project.projectPath);
139→		const organizationId =
140→			flags.org ?? (await getProjectOrgId(project.projectPath));
141→
142→		for (const session of project.sessions) {
143→			completed++;
144→			uploadSpin.message(`[${completed}/${totalSessions}] Uploading...`);
145→
146→			try {
147→				const request = await adapter.buildUploadRequest(session, {
148→					tag: flags.tag,
149→					gitInfo,
150→					organizationId,
151→				});
152→
153→				if (!flags.tag && flags.classify) {
154→					const classified = await classifySession(request.content);
155→					if (classified) {
156→						(request as { tag?: string }).tag = classified;
157→					}
158→				}
159→
160→				if (flags.dryRun) {
161→					succeeded++;
162→					continue;
163→				}
164→
165→				const result = await uploadSession(request, {
166→					...uploadConfig,
167→					onRetry: (attempt, maxAttempts, error) => {
168→						uploadSpin.message(
169→							`[${completed}/${totalSessions}] Retrying (${attempt}/${maxAttempts}) after ${error}`,
170→						);
171→					},
172→				});
173→				if (result.success) {
174→					succeeded++;
175→					await removeFailedUpload(session.sessionId);
176→				} else {
177→					failed++;
178→					const error = result.error ?? "Unknown error";
179→					errors.push({
180→						sessionId: session.sessionId,
181→						project: project.displayPath,
182→						error,
183→					});
184→					await recordFailedUpload({
185→						sessionId: session.sessionId,
186→						transcriptPath: session.transcriptPath,
187→						projectPath: session.projectPath,
188→						source: project.source,
189→						organizationId,
190→						error,
191→					});
192→				}
193→			} catch (error) {
194→				failed++;
195→				const errorMessage =
196→					error instanceof Error ? error.message : String(error);
197→				errors.push({
198→					sessionId: session.sessionId,
199→					project: project.displayPath,
200→					error: errorMessage,
201→				});
202→				await recordFailedUpload({
203→					sessionId: session.sessionId,
204→					transcriptPath: session.transcriptPath,
205→					projectPath: session.projectPath,
206→					source: project.source,
207→					organizationId,
208→					error: errorMessage,
209→				});
210→			}
211→		}
212→	}
213→
214→	uploadSpin.stop("Upload complete");
215→
216→	if (succeeded > 0) {
217→		p.log.success(`${succeeded} session(s) uploaded successfully`);
218→	}
219→	if (failed > 0) {
220→		p.log.error(`${failed} session(s) failed`);
221→		for (const err of errors.slice(0, 5)) {
222→			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
223→		}
224→		if (errors.length > 5) {
225→			p.log.warn(`  ...and ${errors.length - 5} more`);
226→		}
227→		p.log.info("Run `rudel upload --retry` to retry failed uploads.");
228→	}
229→
230→	if (flags.dryRun) {
231→		p.outro("Dry run complete — no sessions were uploaded.");
232→	} else {
233→		p.outro("Done!");
234→	}
235→
236→	if (failed > 0) {
237→		process.exitCode = 1;
238→	}
239→}
240→
241→function getAdapterName(source: string): string {
242→	try {
243→		return getAdapter(source).name;
244→	} catch {
245→		return source;
246→	}
247→}
248→
249→function sessionCountHint(count: number): string {
250→	return `${count} session${count !== 1 ? "s" : ""}`;
251→}
252→
253→async function runSingleUpload(
254→	flags: UploadFlags,
255→	session: string,
256→): Promise<void> {
257→	const write = (msg: string) => {
258→		process.stdout.write(`${msg}\n`);
259→	};
260→	const writeError = (msg: string) => {
261→		process.stderr.write(`${msg}\n`);
262→	};
263→
264→	const credentials = loadCredentials();
265→	if (!credentials && !flags.dryRun) {
266→		writeError("Error: Not authenticated. Run `rudel login` first.");
267→		process.exitCode = 1;
268→		return;
269→	}
270→
271→	write(`Resolving session: ${session}`);
272→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
273→	try {
274→		sessionInfo = await resolveSession(session);
275→	} catch (error) {
276→		writeError(
277→			`Error: ${error instanceof Error ? error.message : String(error)}`,
278→		);
279→		process.exitCode = 1;
280→		return;
281→	}
282→	write(`Found session at: ${sessionInfo.transcriptPath}`);
283→
284→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
285→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
286→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
287→
288→	const organizationId =
289→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
290→	if (organizationId) write(`Organization: ${organizationId}`);
291→
292→	write("Building upload request...");
293→	const sessionFile: SessionFile = {
294→		sessionId: sessionInfo.sessionId,
295→		transcriptPath: sessionInfo.transcriptPath,
296→		projectPath: sessionInfo.projectPath,
297→	};
298→
299→	const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
300→		tag: flags.tag,
301→		gitInfo,
302→		organizationId,
303→	});
304→
305→	write(`Transcript: ${request.content.length} bytes`);
306→	if (request.subagents && request.subagents.length > 0) {
307→		write(`Subagents: ${request.subagents.length} file(s)`);
308→	}
309→
310→	if (!flags.tag && flags.classify) {
311→		write("Classifying session...");
312→		const classified = await classifySession(request.content);
313→		if (classified) {
314→			(request as { tag?: string }).tag = classified;
315→			write(`Classified as: ${classified}`);
316→		}
317→	}
318→
319→	if (flags.dryRun) {
320→		const preview = {
321→			...request,
322→			content: `[${request.content.length} bytes]`,
323→			subagents: request.subagents?.map((s) => ({
324→				...s,
325→				content: `[${s.content.length} bytes]`,
326→			})),
327→		};
328→		write("Dry run - would upload:");
329→		write(JSON.stringify(preview, null, 2));
330→		return;
331→	}
332→
333→	write("Uploading...");
334→	const result = await uploadSession(request, {
335→		endpoint: flags.endpoint,
336→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
337→		token: credentials!.token,
338→	});
339→
340→	if (result.success) {
341→		write("Upload successful!");
342→	} else {
343→		writeError(`Upload failed: ${result.error}`);
344→		process.exitCode = 1;
345→	}
346→}
347→
348→async function runRetryUpload(flags: UploadFlags): Promise<void> {
349→	const credentials = loadCredentials();
350→	if (!credentials) {
351→		p.log.error("Not authenticated. Run `rudel login` first.");
352→		process.exitCode = 1;
353→		return;
354→	}
355→
356→	p.intro("rudel upload --retry");
357→
358→	const failures = await loadFailedUploads();
359→	if (failures.length === 0) {
360→		p.outro("No failed uploads to retry.");
361→		return;
362→	}
363→
364→	p.log.info(`Found ${failures.length} failed upload(s):`);
365→	for (const f of failures.slice(0, 10)) {
366→		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
367→	}
368→	if (failures.length > 10) {
369→		p.log.warn(`  ...and ${failures.length - 10} more`);
370→	}
371→
372→	const shouldRetry = await p.confirm({
373→		message: `Retry all ${failures.length} failed upload(s)?`,
374→		initialValue: true,
375→	});
376→
377→	if (p.isCancel(shouldRetry) || !shouldRetry) {
378→		p.cancel("Retry cancelled.");
379→		return;
380→	}
381→
382→	const endpoint = flags.endpoint;
383→	let succeeded = 0;
384→	let failed = 0;
385→
386→	await p.tasks(
387→		failures.map((failure, i) => ({
388→			title: `[${i + 1}/${failures.length}] ${failure.sessionId}`,
389→			task: async (message: (msg: string) => void) => {
390→				const prefix = `[${i + 1}/${failures.length}]`;
391→				try {
392→					message("Building upload request...");
393→					const adapter = failure.source
394→						? getAdapter(failure.source)
395→						: claudeCodeAdapter;
396→					const sessionFile: SessionFile = {
397→						sessionId: failure.sessionId,
398→						transcriptPath: failure.transcriptPath,
399→						projectPath: failure.projectPath,
400→					};
401→					const gitInfo = await getGitInfo(failure.projectPath);
402→					const organizationId =
403→						flags.org ??
404→						failure.organizationId ??
405→						(await getProjectOrgId(failure.projectPath));
406→
407→					const request = await adapter.buildUploadRequest(sessionFile, {
408→						tag: flags.tag,
409→						gitInfo,
410→						organizationId,
411→					});
412→
413→					message("Uploading...");
414→					const result = await uploadSession(request, {
415→						endpoint,
416→						token: credentials.token,
417→						onRetry: (attempt, maxAttempts, error) => {
418→							message(
419→								`${prefix} Retrying (${attempt}/${maxAttempts}) after ${error}...`,
420→							);
421→						},
422→					});
423→
424→					if (result.success) {
425→						succeeded++;
426→						await removeFailedUpload(failure.sessionId);
427→						const retryNote =
428→							result.attempts && result.attempts > 1
429→								? ` (after ${result.attempts} attempts)`
430→								: "";
431→						return `Uploaded${retryNote}`;
432→					}
433→					failed++;
434→					await recordFailedUpload({
435→						...failure,
436→						error: result.error ?? "Unknown error",
437→					});
438→					return `Failed: ${result.error}`;
439→				} catch (error) {
440→					failed++;
441→					const errorMessage =
442→						error instanceof Error ? error.message : String(error);
443→					await recordFailedUpload({ ...failure, error: errorMessage });
444→					return `Error: ${errorMessage}`;
445→				}
446→			},
447→		})),
448→	);
449→
450→	if (succeeded > 0) {
451→		p.log.success(`${succeeded} session(s) uploaded`);
452→	}
453→	if (failed > 0) {
454→		p.log.error(`${failed} session(s) still failing`);
455→	}
456→
457→	p.outro("Done!");
458→
459→	if (failed > 0) {
460→		process.exitCode = 1;
461→	}
462→}
463→
464→async function runUpload(
465→	flags: UploadFlags,
466→	...sessions: string[]
467→): Promise<void> {
468→	if (flags.retry) {
469→		return runRetryUpload(flags);
470→	}
471→	if (sessions.length === 0) {
472→		return runInteractiveUpload(flags);
473→	}
474→	return runSingleUpload(flags, sessions[0] as string);
475→}
476→
477→export const uploadCommand = buildCommand({
478→	loader: async () => ({ default: runUpload }),
479→	parameters: {
480→		positional: {
481→			kind: "array",
482→			parameter: {
483→				brief: "Session ID or path to a session .jsonl file",
484→				parse: String,
485→				placeholder: "session",
486→			},
487→		},
488→		flags: {
489→			tag: {
490→				kind: "enum",
491→				values: [...SESSION_TAGS],
492→				brief: "Session tag/category",
493→				optional: true,
494→			},
495→			endpoint: {
496→				kind: "parsed",
497→				parse: String,
498→				brief: "Override the upload endpoint URL",
499→				default: DEFAULT_ENDPOINT,
500→			},
501→			classify: {
502→				kind: "boolean",
503→				brief: "Auto-classify session tag using Claude CLI",
504→				default: false,
505→			},
506→			dryRun: {
507→				kind: "boolean",
508→				brief: "Preview what would be uploaded without sending",
509→				default: false,
510→			},
511→			org: {
512→				kind: "parsed",
513→				parse: String,
514→				brief: "Override the organization ID to upload to",
515→				optional: true,
516→			},
517→			retry: {
518→				kind: "boolean",
519→				brief: "Retry previously failed uploads",
520→				default: false,
521→			},
522→		},
523→		aliases: {
524→			t: "tag",
525→			c: "classify",
526→			n: "dryRun",
527→			o: "org",
528→			r: "retry",
529→		},
530→	},
531→	docs: {
532→		brief:
533→			"Upload session transcripts (Claude Code & Codex). No args = interactive project picker.",
534→	},
535→});
