 1→import { createORPCClient, ORPCError } from "@orpc/client";
 2→import { RPCLink } from "@orpc/client/fetch";
 3→import type { ContractRouterClient } from "@orpc/contract";
 4→import type { contract, IngestSessionInput } from "@rudel/api-routes";
 5→import type { UploadResult } from "./types.js";
 6→
 7→export interface UploadConfig {
 8→	endpoint: string;
 9→	token: string;
10→	onRetry?: (attempt: number, maxAttempts: number, error: string) => void;
11→}
12→
13→const RETRYABLE_STATUS_CODES = new Set([502, 503, 429]);
14→const MAX_ATTEMPTS = 3;
15→const BASE_DELAY_MS = 1_000;
16→
17→function isRetryable(error: unknown): boolean {
18→	if (error instanceof ORPCError) {
19→		return RETRYABLE_STATUS_CODES.has(error.status);
20→	}
21→	if (error instanceof TypeError) {
22→		return true; // network errors (fetch failures)
23→	}
24→	return false;
25→}
26→
27→function formatError(error: unknown): string {
28→	if (error instanceof ORPCError) {
29→		return `${error.status} ${error.message}`;
30→	}
31→	if (error instanceof Error) {
32→		return error.message;
33→	}
34→	return String(error);
35→}
36→
37→/**
38→ * Upload a session transcript to the backend via oRPC.
39→ * Retries on transient errors (502, 503, 429) with exponential backoff.
40→ */
41→export async function uploadSession(
42→	request: IngestSessionInput,
43→	config: UploadConfig,
44→): Promise<UploadResult> {
45→	const link = new RPCLink({
46→		url: config.endpoint,
47→		headers: {
48→			Authorization: `Bearer ${config.token}`,
49→		},
50→	});
51→
52→	const client: ContractRouterClient<typeof contract> = createORPCClient(link);
53→
54→	for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
55→		try {
56→			await client.ingestSession(request);
57→			return { success: true, status: 200, attempts: attempt };
58→		} catch (error) {
59→			const errorMessage = formatError(error);
60→
61→			if (isRetryable(error) && attempt < MAX_ATTEMPTS) {
62→				config.onRetry?.(attempt, MAX_ATTEMPTS, errorMessage);
63→				const delay = BASE_DELAY_MS * 2 ** (attempt - 1);
64→				await new Promise((resolve) => setTimeout(resolve, delay));
65→				continue;
66→			}
67→
68→			return {
69→				success: false,
70→				error: errorMessage,
71→				attempts: attempt,
72→			};
73→		}
74→	}
75→
76→	return {
77→		success: false,
78→		error: "Max retries exceeded",
79→		attempts: MAX_ATTEMPTS,
80→	};
81→}
