12→async function runHookUpload(): Promise<void> {
13→	await setupHookLogging();
14→	const logger = getLogger(["rudel", "cli", "hook"]);
15→
16→	try {
17→		logger.debug("Hook upload started");
18→
19→		const config = await readConfig();
20→
21→		if (!config.apiKey) {
22→			logger.debug("Not logged in, skipping session upload.");
23→			return;
24→		}
25→
26→		const stdinContent = await readStdin();
27→		const input = parseStdinInput(stdinContent);
28→
29→		if (!input) {
30→			logger.debug("No stdin input, exiting.");
31→			return;
32→		}
33→
34→		const { session_id, transcript_path, cwd } = input;
35→		if (!session_id || !transcript_path) {
36→			logger.error("Missing session_id or transcript_path");
37→			return;
38→		}
39→
40→		const sessionFile: SessionFile = {
41→			sessionId: session_id,
42→			transcriptPath: transcript_path,
43→			projectPath: cwd,
44→		};
45→
46→		const gitInfo = await getGitInfo(cwd);
47→
48→		const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
49→			gitInfo,
50→		});
51→
52→		const tag = await classifySession(request.content);
53→		if (tag) {
54→			(request as { tag?: string }).tag = tag;
55→		}
56→
57→		const endpoint =
58→			process.env.GAZED_INGEST_ENDPOINT ?? config.endpoint ?? DEFAULT_ENDPOINT;
59→
60→		logger.info(
61→			"Uploading session {sessionId}, repo={repository}, branch={branch}, tag={tag}, bytes={bytes}, subagents={subagents}",
62→			{
63→				sessionId: request.sessionId,
64→				repository: request.repository ?? "none",
65→				branch: request.gitBranch ?? "none",
66→				tag: request.tag ?? "none",
67→				bytes: request.content.length,
68→				subagents: request.subagents?.length ?? 0,
69→			},
70→		);
71→
72→		const result = await uploadSession(request, {
73→			endpoint,
74→			token: config.apiKey,
75→		});
76→
77→		if (result.success) {
78→			logger.info("Upload successful for session {sessionId}", {
79→				sessionId: request.sessionId,
80→			});
81→		} else {
82→			logger.error("Upload failed: {error}", { error: result.error });
83→		}
84→	} catch (error) {
85→		logger.error("Unexpected error: {error}", { error });
86→	} finally {
87→		await disposeLogging();
88→	}
89→}
