 29→	await setupHookLogging();
 30→	const logger = getLogger(["rudel", "cli", "hook"]);
 31→
 32→	try {
 33→		const raw = await readStdin();
 34→		if (!raw.trim()) return;
 35→
 36→		const input = JSON.parse(raw) as HookInput;
 37→		if (!input.session_id || !input.transcript_path) return;
 38→
 39→		const credentials = loadCredentials();
 40→		if (!credentials) return;
 41→
 42→		logger.info("Uploading session {sessionId}", {
 43→			sessionId: input.session_id,
 44→		});
 45→
 46→		const sessionFile: SessionFile = {
 47→			sessionId: input.session_id,
 48→			transcriptPath: input.transcript_path,
 49→			projectPath: input.cwd,
 50→		};
 51→
 52→		const gitInfo = await getGitInfo(input.cwd);
 53→		const organizationId = await getProjectOrgId(input.cwd);
 54→
 55→		const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
 56→			gitInfo,
 57→			organizationId,
 58→		});
 59→
 60→		const apiBase = process.env.RUDEL_API_BASE ?? credentials.apiBaseUrl;
 61→		const endpoint = `${apiBase}/rpc`;
 62→		const result = await uploadSession(request, {
 63→			endpoint,
 64→			token: credentials.token,
 65→			onRetry: (attempt, maxAttempts, error) => {
 66→				logger.warn(
 67→					"Retrying upload for {sessionId} ({attempt}/{maxAttempts}): {error}",
 68→					{ sessionId: input.session_id, attempt, maxAttempts, error },
 69→				);
 70→			},
 71→		});
 72→
 73→		if (result.success) {
 74→			logger.info(
 75→				"Upload successful for session {sessionId} (attempts: {attempts})",
 76→				{ sessionId: input.session_id, attempts: result.attempts },
 77→			);
 78→			await removeFailedUpload(input.session_id);
 79→		} else {
 80→			logger.error("Upload failed for session {sessionId}: {error}", {
 81→				sessionId: input.session_id,
 82→				error: result.error,
 83→			});
 84→			await recordFailedUpload({
 85→				sessionId: input.session_id,
 86→				transcriptPath: input.transcript_path,
 87→				projectPath: input.cwd,
 88→				source: "claude-code",
 89→				organizationId,
 90→				error: result.error ?? "Unknown error",
 91→			});
 92→		}
 93→	} catch (error) {
 94→		logger.error("Session end hook failed: {error}", { error });
 95→	} finally {
 96→		await disposeLogging();
 97→	}
 98→}
