24→async function readStdin(): Promise<string> {
25→	const chunks: string[] = [];
26→	for await (const chunk of process.stdin) {
27→		chunks.push(typeof chunk === "string" ? chunk : chunk.toString());
28→	}
29→	return chunks.join("");
30→}
