32→async function runTurnComplete(): Promise<void> {
33→	try {
34→		const raw = await readStdin();
35→		if (!raw.trim()) return;
36→
37→		const input = JSON.parse(raw) as CodexNotifyInput;
38→		if (!input.thread_id || !input.cwd) return;
39→
40→		const credentials = loadCredentials();
41→		if (!credentials) return;
42→
43→		const transcriptPath =
44→			input.transcript_path ?? (await findActiveRolloutFile(input.thread_id));
45→		if (!transcriptPath) return;
46→
47→		const sessionFile: SessionFile = {
48→			sessionId: input.thread_id,
49→			transcriptPath,
50→			projectPath: input.cwd,
51→		};
52→
53→		const gitInfo = await getGitInfo(input.cwd);
54→		const organizationId = await getProjectOrgId(input.cwd);
55→
56→		const request = await codexAdapter.buildUploadRequest(sessionFile, {
57→			gitInfo,
58→			organizationId,
59→		});
60→
61→		const apiBase = process.env.RUDEL_API_BASE ?? credentials.apiBaseUrl;
62→		const endpoint = `${apiBase}/rpc`;
63→		const result = await uploadSession(request, {
64→			endpoint,
65→			token: credentials.token,
66→		});
67→
68→		if (result.success) {
69→			await removeFailedUpload(input.thread_id);
70→		} else {
71→			await recordFailedUpload({
72→				sessionId: input.thread_id,
73→				transcriptPath,
74→				projectPath: input.cwd,
75→				source: "codex",
76→				organizationId,
77→				error: result.error ?? "Unknown error",
78→			});
79→		}
80→	} catch {
81→		// Swallow all errors — this runs async in the background
82→	}
83→}
