 44→	test("uploads a session via uploadSession to the local API", async () => {
 45→		expect(bearerToken).toBeTruthy();
 46→
 47→		const testId = `cli_api_test_${Date.now()}`;
 48→		const request: IngestSessionInput = {
 49→			source: "claude_code",
 50→			sessionId: testId,
 51→			projectPath: "/test/cli-api-upload",
 52→			repository: "test-repo",
