 55→			tag: "tests",
 56→			content: "cli api integration test content",
 57→			subagents: [{ agentId: "sub-1", content: "subagent content" }],
 58→		};
 59→
 60→		// Retry up to 3 times — Bun may kill the server as a "dangling process"
 61→		// and the restarted server's ClickHouse connection can be slow to warm up.
 62→		// Each attempt has a per-call timeout so a hanging request doesn't
 63→		// consume the entire test timeout and block retries.
 64→		let result = { success: false, error: "not attempted" } as Awaited<
 65→			ReturnType<typeof uploadSession>
