 71→					token: bearerToken,
 72→				}),
 73→				Bun.sleep(15_000).then(
 74→					() =>
 75→						({ success: false, error: "attempt timed out" }) as Awaited<
 76→							ReturnType<typeof uploadSession>
 77→						>,
 78→				),
 79→			]);
 80→			if (result.success) break;
 81→			await server.ensureAlive();
 82→			await Bun.sleep(1000);
 83→		}
 84→
 85→		if (!result.success) {
 86→			throw new Error(`uploadSession failed after 3 attempts: ${result.error}`);
 87→		}
 88→		expect(result.status).toBe(200);
 89→	}, 60_000);
