102→			JSON.stringify({ token: bearerToken, apiBaseUrl: server.baseUrl }),
103→		);
104→
105→		const sessionFile = join(projectDir, "e2e-test-session.jsonl");
106→		await writeFile(
107→			sessionFile,
108→			[
109→				JSON.stringify({
