115→					role: "human",
116→					content: "test",
117→				}),
118→			].join("\n"),
119→		);
120→
121→		const cliPath = join(import.meta.dir, "..", "bin", "cli.ts");
122→
123→		// Retry up to 3 times — same dangling-process issue as the direct-call test.
124→		// Each subprocess gets a per-attempt timeout so a hanging process
125→		// doesn't consume the entire test timeout.
126→		let lastStdout = "";
127→		let lastStderr = "";
128→		let lastExitCode = -1;
129→		for (let attempt = 0; attempt < 3; attempt++) {
130→			const proc = Bun.spawn(
