141→			);
142→
143→			const timeout = setTimeout(() => proc.kill(), 15_000);
144→			const [exitCode, stdout, stderr] = await Promise.all([
145→				proc.exited,
146→				new Response(proc.stdout).text(),
147→				new Response(proc.stderr).text(),
148→			]);
149→			clearTimeout(timeout);
150→
151→			lastStdout = stdout;
152→			lastStderr = stderr;
153→			lastExitCode = exitCode;
154→
155→			if (stdout.includes("Upload successful!")) break;
156→			await server.ensureAlive();
