  1→import * as p from "@clack/prompts";
  2→import { type AgentAdapter, getAvailableAdapters } from "@rudel/agent-adapters";
  3→import { buildCommand } from "@stricli/core";
  4→import { createApiClient } from "../lib/api-client.js";
  5→import { verifyAuth } from "../lib/auth.js";
  6→import {
  7→	recordFailedUpload,
  8→	removeFailedUpload,
  9→} from "../lib/failed-uploads.js";
 10→import { getGitInfo } from "../lib/git-info.js";
 11→import { getProjectOrgId, setProjectOrgId } from "../lib/project-config.js";
 12→import { uploadSession } from "../lib/uploader.js";
 13→
 14→async function runEnable(): Promise<void> {
 15→	p.intro("rudel enable");
 16→
 17→	// Verify auth (loads credentials + pings API)
 18→	const auth = await verifyAuth();
 19→	if (!auth.authenticated) {
 20→		p.log.error(auth.message);
 21→		p.outro("Run `rudel login` to authenticate.");
 22→		process.exitCode = 1;
 23→		return;
 24→	}
 25→
 26→	const { credentials } = auth;
 27→
 28→	// Fetch user's organizations
 29→	const client = createApiClient(credentials);
 30→	let orgs: { id: string; name: string; slug: string }[];
 31→	try {
 32→		orgs = await client.listMyOrganizations();
 33→	} catch {
 34→		p.log.error("Failed to fetch organizations. Check your connection.");
 35→		process.exitCode = 1;
 36→		return;
 37→	}
 38→
 39→	if (orgs.length === 0) {
 40→		p.log.error("No organizations found.");
 41→		p.outro("Create one at app.rudel.ai first.");
 42→		process.exitCode = 1;
 43→		return;
 44→	}
 45→
 46→	// Check if already configured for this project
 47→	const cwd = process.cwd();
 48→	const existingOrgId = await getProjectOrgId(cwd);
 49→	const existingOrg = existingOrgId
 50→		? orgs.find((o) => o.id === existingOrgId)
 51→		: undefined;
 52→
 53→	let selectedOrgId: string;
 54→
 55→	const [firstOrg] = orgs;
 56→	if (orgs.length === 1 && firstOrg) {
 57→		selectedOrgId = firstOrg.id;
 58→		p.log.info(`Using organization: ${firstOrg.name}`);
 59→	} else if (existingOrg) {
 60→		p.log.info(`Currently configured for: ${existingOrg.name}`);
 61→		selectedOrgId = existingOrg.id;
 62→	} else {
 63→		const selected = await p.select({
 64→			message: "Select an organization for this repository",
 65→			options: orgs.map((org) => ({
 66→				value: org.id,
 67→				label: org.name,
 68→				hint: org.slug,
 69→			})),
 70→		});
 71→
 72→		if (p.isCancel(selected)) {
 73→			p.cancel("Setup cancelled.");
 74→			return;
 75→		}
 76→
 77→		selectedOrgId = selected;
 78→		const selectedOrg = orgs.find((o) => o.id === selected);
 79→		if (selectedOrg) {
 80→			p.log.success(`Selected: ${selectedOrg.name}`);
 81→		}
 82→	}
 83→
 84→	await setProjectOrgId(cwd, selectedOrgId);
 85→
 86→	// Detect available agents and install hooks
 87→	const adapters = getAvailableAdapters();
 88→	let adaptersToEnable: AgentAdapter[];
 89→
 90→	if (adapters.length > 1) {
 91→		const agentOptions = adapters.map((a) => ({
 92→			value: a,
 93→			label: a.name,
 94→			hint: a.isHookInstalled() ? "already enabled" : undefined,
 95→		}));
 96→		const selectedAdapters = await p.multiselect({
 97→			message: "Select agents to enable auto-upload for",
 98→			options: agentOptions,
 99→			initialValues: adapters,
100→			required: true,
101→		});
102→
103→		if (p.isCancel(selectedAdapters)) {
104→			p.cancel("Setup cancelled.");
105→			return;
106→		}
107→		adaptersToEnable = selectedAdapters;
108→	} else {
109→		adaptersToEnable = adapters;
110→	}
111→
112→	for (const adapter of adaptersToEnable) {
113→		if (adapter.isHookInstalled()) {
114→			p.log.info(
115→				`${adapter.name}: Auto-upload hook is already enabled. Organization updated.`,
116→			);
117→		} else {
118→			adapter.installHook();
119→			p.log.success(
120→				`${adapter.name}: Auto-upload hook enabled in ${adapter.getHookConfigPath()}`,
121→			);
122→		}
123→	}
124→
125→	// Check for existing sessions to upload from all enabled agents
126→	const endpoint = `${credentials.apiBaseUrl}/rpc`;
127→	let totalFailed = 0;
128→
129→	for (const adapter of adaptersToEnable) {
130→		const sessions = await adapter.findProjectSessions(cwd);
131→		if (sessions.length === 0) continue;
132→
133→		const shouldUpload = await p.confirm({
134→			message: `Found ${sessions.length} previous ${adapter.name} session(s). Upload them now?`,
135→			initialValue: false,
136→		});
137→
138→		if (p.isCancel(shouldUpload) || !shouldUpload) continue;
139→
140→		const gitInfo = await getGitInfo(cwd);
141→		let succeeded = 0;
142→		let failed = 0;
143→		const errors: Array<{ sessionId: string; error: string }> = [];
144→
145→		await p.tasks(
146→			sessions.map((session, i) => ({
147→				title: `[${i + 1}/${sessions.length}] ${session.sessionId}`,
148→				task: async (message: (msg: string) => void) => {
149→					const prefix = `[${i + 1}/${sessions.length}]`;
150→					try {
151→						message("Building upload request...");
152→						const request = await adapter.buildUploadRequest(session, {
153→							gitInfo,
154→							organizationId: selectedOrgId,
155→						});
156→
157→						message("Uploading...");
158→						const result = await uploadSession(request, {
159→							endpoint,
160→							token: credentials.token,
161→							onRetry: (attempt, maxAttempts, error) => {
162→								message(
163→									`${prefix} Retrying (${attempt}/${maxAttempts}) after ${error}...`,
164→								);
165→							},
166→						});
167→
168→						if (result.success) {
169→							succeeded++;
170→							await removeFailedUpload(session.sessionId);
171→							const retryNote =
172→								result.attempts && result.attempts > 1
173→									? ` (after ${result.attempts} attempts)`
174→									: "";
175→							return `Uploaded${retryNote}`;
176→						}
177→						failed++;
178→						const uploadError = result.error ?? "Unknown error";
179→						errors.push({ sessionId: session.sessionId, error: uploadError });
180→						await recordFailedUpload({
181→							sessionId: session.sessionId,
182→							transcriptPath: session.transcriptPath,
183→							projectPath: session.projectPath,
184→							source: adapter.source,
185→							organizationId: selectedOrgId,
186→							error: uploadError,
187→						});
188→						return `Failed: ${result.error}`;
189→					} catch (error) {
190→						failed++;
191→						const errorMessage =
192→							error instanceof Error ? error.message : String(error);
193→						errors.push({ sessionId: session.sessionId, error: errorMessage });
194→						await recordFailedUpload({
195→							sessionId: session.sessionId,
196→							transcriptPath: session.transcriptPath,
197→							projectPath: session.projectPath,
198→							source: adapter.source,
199→							organizationId: selectedOrgId,
200→							error: errorMessage,
201→						});
202→						return `Error: ${errorMessage}`;
203→					}
204→				},
205→			})),
206→		);
207→
208→		if (succeeded > 0) {
209→			p.log.success(`${succeeded} ${adapter.name} session(s) uploaded`);
210→		}
211→		if (failed > 0) {
212→			p.log.error(`${failed} ${adapter.name} session(s) failed`);
213→			for (const err of errors.slice(0, 5)) {
214→				p.log.warn(`  ${err.sessionId}: ${err.error}`);
215→			}
216→			if (errors.length > 5) {
217→				p.log.warn(`  ...and ${errors.length - 5} more`);
218→			}
219→		}
220→		totalFailed += failed;
221→	}
222→
223→	if (totalFailed > 0) {
224→		p.log.info("Run `rudel upload --retry` to retry failed uploads.");
225→	}
226→
227→	p.outro("Done!");
228→
229→	if (totalFailed > 0) {
230→		process.exitCode = 1;
231→	}
232→}
233→
234→export const enableCommand = buildCommand({
235→	loader: async () => ({ default: runEnable }),
236→	parameters: {},
237→	docs: {
238→		brief: "Enable automatic session upload for coding agents",
239→	},
240→});
