const gitInfo = await getGitInfo(cwd);
let succeeded = 0;
let failed = 0;
let completed = 0;
const errors: Array<{ sessionId: string; error: string }> = [];

const enableSpin = p.spinner();
enableSpin.start(`Uploading ${adapter.name} sessions...`);

await concurrentMap(
	sessions,
	async (session) => {
		try {
			const request = await adapter.buildUploadRequest(session, {
				gitInfo,
				organizationId: selectedOrgId,
			});

			const result = await uploadSession(request, {
				endpoint,
				token: credentials.token,
				onRetry: (attempt, maxAttempts, error) => {
					enableSpin.message(
						`[${completed + 1}/${sessions.length}] Retrying (${attempt}/${maxAttempts}) after ${error}...`,
					);
				},
			});

			if (result.success) {
				succeeded++;
				await removeFailedUpload(session.sessionId);
			} else {
				failed++;
				const uploadError = result.error ?? "Unknown error";
				errors.push({ sessionId: session.sessionId, error: uploadError });
				await recordFailedUpload({
					sessionId: session.sessionId,
					transcriptPath: session.transcriptPath,
					projectPath: session.projectPath,
					source: adapter.source,
					organizationId: selectedOrgId,
					error: uploadError,
				});
			}
		} catch (error) {
			failed++;
			const errorMessage =
				error instanceof Error ? error.message : String(error);
			errors.push({ sessionId: session.sessionId, error: errorMessage });
			await recordFailedUpload({
				sessionId: session.sessionId,
				transcriptPath: session.transcriptPath,
				projectPath: session.projectPath,
				source: adapter.source,
				organizationId: selectedOrgId,
				error: errorMessage,
			});
		} finally {
			completed++;
			enableSpin.message(
				`[${completed}/${sessions.length}] Uploading ${adapter.name} sessions...`,
			);
		}
	},
	DEFAULT_CONCURRENCY,
);

enableSpin.stop("Upload complete");

