  1→import { randomBytes } from "node:crypto";
  2→import * as p from "@clack/prompts";
  3→import { buildCommand } from "@stricli/core";
  4→import { loadCredentials, saveCredentials } from "../lib/credentials.js";
  5→
  6→const DEFAULT_API_BASE = "https://app.rudel.ai";
  7→const DEFAULT_WEB_URL = "https://app.rudel.ai";
  8→const CALLBACK_TIMEOUT_MS = 120_000;
  9→
 10→async function runLogin(flags: {
 11→	apiBase: string;
 12→	webUrl: string;
 13→	noBrowser: boolean;
 14→}): Promise<void> {
 15→	p.intro("rudel login");
 16→
 17→	const existing = loadCredentials();
 18→	if (existing) {
 19→		p.log.warn("Already logged in.");
 20→		p.outro("Run `rudel logout` first to switch accounts.");
 21→		return;
 22→	}
 23→
 24→	const state = randomBytes(16).toString("hex");
 25→
 26→	let resolveCallback: (token: string) => void;
 27→	let rejectCallback: (error: Error) => void;
 28→	const tokenPromise = new Promise<string>((resolve, reject) => {
 29→		resolveCallback = resolve;
 30→		rejectCallback = reject;
 31→	});
 32→
 33→	const server = Bun.serve({
 34→		port: 0,
 35→		hostname: "127.0.0.1",
 36→		fetch(request) {
 37→			const url = new URL(request.url);
 38→			if (url.pathname !== "/callback") {
 39→				return new Response("Not found", { status: 404 });
 40→			}
 41→
 42→			const receivedToken = url.searchParams.get("token");
 43→			const receivedState = url.searchParams.get("state");
 44→
 45→			if (receivedState !== state) {
 46→				rejectCallback(new Error("State mismatch — possible CSRF attack"));
 47→				return new Response(
 48→					"<html><body><h1>Login failed</h1><p>State mismatch. Please try again.</p></body></html>",
 49→					{ headers: { "Content-Type": "text/html" } },
 50→				);
 51→			}
 52→
 53→			if (!receivedToken) {
 54→				rejectCallback(new Error("No token received"));
 55→				return new Response(
 56→					"<html><body><h1>Login failed</h1><p>No token received.</p></body></html>",
 57→					{ headers: { "Content-Type": "text/html" } },
 58→				);
 59→			}
 60→
 61→			resolveCallback(receivedToken);
 62→			return new Response(
 63→				"<html><body><h1>Login successful!</h1><p>You can close this tab and return to the terminal.</p></body></html>",
 64→				{ headers: { "Content-Type": "text/html" } },
 65→			);
 66→		},
 67→	});
 68→
 69→	const callbackUrl = `http://127.0.0.1:${server.port}/callback`;
 70→	const loginUrl = `${flags.webUrl}?cli_callback=${encodeURIComponent(callbackUrl)}&state=${state}`;
 71→
 72→	p.log.info(`If the browser doesn't open, visit:\n${loginUrl}`);
 73→
 74→	// Open browser
 75→	if (!flags.noBrowser) {
 76→		if (process.platform === "win32") {
 77→			Bun.spawn(["cmd", "/c", "start", "", loginUrl], {
 78→				stdout: "ignore",
 79→				stderr: "ignore",
 80→			});
 81→		} else {
 82→			const opener = process.platform === "darwin" ? "open" : "xdg-open";
 83→			Bun.spawn([opener, loginUrl], { stdout: "ignore", stderr: "ignore" });
 84→		}
 85→	}
 86→
 87→	// Wait for callback with timeout
 88→	const timeout = setTimeout(() => {
 89→		rejectCallback(new Error("Login timed out after 120 seconds"));
 90→	}, CALLBACK_TIMEOUT_MS);
 91→
 92→	const spin = p.spinner();
 93→	spin.start("Waiting for browser authentication...");
 94→
 95→	let token: string;
 96→	try {
 97→		token = await tokenPromise;
 98→	} catch (error) {
 99→		clearTimeout(timeout);
100→		server.stop();
101→		spin.stop("Authentication failed");
102→		p.log.error(error instanceof Error ? error.message : String(error));
103→		process.exitCode = 1;
104→		return;
105→	}
106→	clearTimeout(timeout);
107→	server.stop();
108→
109→	spin.message("Validating token...");
110→
111→	// Validate token via /rpc/me
112→	const meResponse = await fetch(`${flags.apiBase}/rpc/me`, {
113→		method: "POST",
114→		headers: {
115→			"Content-Type": "application/json",
116→			Authorization: `Bearer ${token}`,
117→		},
118→		body: JSON.stringify({}),
119→	});
120→
121→	if (!meResponse.ok) {
122→		spin.stop("Token validation failed");
123→		p.log.error("Login failed: token validation failed");
124→		process.exitCode = 1;
125→		return;
126→	}
127→
128→	const body = (await meResponse.json()) as {
