 55→		const projects = await adapter.scanAllSessions();
 56→		allProjects.push(...projects);
 57→	}
 58→
 59→	spin.stop(`Found ${allProjects.length} project(s)`);
 60→
 61→	if (allProjects.length === 0) {
 62→		p.log.warn("No projects with sessions found.");
 63→		p.outro("Nothing to upload.");
 64→		return;
 65→	}
 66→
 67→	const cwd = process.cwd();
 68→	const grouped = groupProjectsForCwd(allProjects, cwd);
 69→
 70→	const options: Array<{
 71→		value: ScannedProject;
 72→		label: string;
 73→		hint: string;
 74→	}> = [];
 75→	const preSelected: ScannedProject[] = [];
 76→
 77→	for (const proj of grouped.current) {
 78→		options.push({
 79→			value: proj,
 80→			label: `[${getAdapterName(proj.source)}] ${proj.displayPath}`,
 81→			hint: sessionCountHint(proj.sessionCount),
 82→		});
 83→		preSelected.push(proj);
 84→	}
 85→
 86→	for (const sub of grouped.subfolders) {
 87→		const relative = sub.projectPath.slice(cwd.length + 1);
 88→		options.push({
 89→			value: sub,
 90→			label: `  [${getAdapterName(sub.source)}] ${relative}`,
 91→			hint: sessionCountHint(sub.sessionCount),
 92→		});
 93→		preSelected.push(sub);
 94→	}
 95→
 96→	for (const other of grouped.others) {
 97→		options.push({
 98→			value: other,
 99→			label: `[${getAdapterName(other.source)}] ${other.displayPath}`,
100→			hint: sessionCountHint(other.sessionCount),
101→		});
102→	}
103→
104→	const selected = await p.multiselect({
105→		message: "Select projects to upload",
106→		options,
107→		initialValues: preSelected,
108→		required: true,
109→	});
110→
111→	if (p.isCancel(selected)) {
112→		p.cancel("Upload cancelled.");
113→		return;
114→	}
115→
116→	const totalSessions = selected.reduce(
117→		(sum, proj) => sum + proj.sessionCount,
118→		0,
119→	);
120→	p.log.info(
