				}

				const result = await uploadSession(request, {
					...uploadConfig,
					onRetry: (attempt, maxAttempts, error) => {
						uploadSpin.message(
							`[${completed + 1}/${totalSessions}] Retrying (${attempt}/${maxAttempts}) after ${error}`,
						);
